    'pchip', 'nearest');

F_tyx_imag = griddedInterpolant(phase_state_rad, imag(t_yx_samples), ...
    'pchip', 'nearest');

F_tyy_real = griddedInterpolant(phase_state_rad, real(t_yy_samples), ...
    'pchip', 'nearest');

F_tyy_imag = griddedInterpolant(phase_state_rad, imag(t_yy_samples), ...
    'pchip', 'nearest');

